mapper.select:
SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM STUDENT
WHERE STD_USER_ID = #{studentId}
  AND PRNT_USER_ID = #{parentId}

SELECT
    ATND_SN      AS atndSn,
    STD_USER_ID  AS stdUserId,
    ATND_TYPE_CD AS atndTypeCd,
    ATND_REG_DT  AS atndRegDt
FROM STUDENT_ATTENDANCE
WHERE STD_USER_ID = #{studentId}
  AND EXTRACT(YEAR  FROM ATND_REG_DT) = #{year}
  AND EXTRACT(MONTH FROM ATND_REG_DT) = #{month}
ORDER BY ATND_REG_DT
